def has_cycle(n, edges):
    graph = [[] for _ in range(n + 1)]
    for u, v in edges:
        graph[u].append(v)

    state = [0] * (n + 1)  # 0 = unvisited, 1 = visiting, 2 = done

    def dfs(node):
        if state[node] == 1:
            return True
        if state[node] == 2:
            return False

        state[node] = 1
        for nei in graph[node]:
            if dfs(nei):
                return True
        state[node] = 2
        return False

    for node in range(1, n + 1):
        if state[node] == 0 and dfs(node):
            return True
    return False
```

