function isPlainObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function deepMerge(a, b) {
  if (!isPlainObject(a) || !isPlainObject(b)) {
    throw new TypeError('deepMerge expects two plain objects');
  }

  const result = {};
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);

  for (const key of keys) {
    const hasA = Object.prototype.hasOwnProperty.call(a, key);
    const hasB = Object.prototype.hasOwnProperty.call(b, key);

    if (!hasB) {
      result[key] = cloneValue(a[key]);
      continue;
    }

    if (!hasA) {
      result[key] = cloneValue(b[key]);
      continue;
    }

    const aValue = a[key];
    const bValue = b[key];

    if (isPlainObject(aValue) && isPlainObject(bValue)) {
      result[key] = deepMerge(aValue, bValue);
    } else {
      result[key] = cloneValue(bValue);
    }
  }

  return result;
}

function cloneValue(value) {
  if (Array.isArray(value)) {
    return value.map(cloneValue);
  }

  if (isPlainObject(value)) {
    const copy = {};
    for (const key of Object.keys(value)) {
      copy[key] = cloneValue(value[key]);
    }
    return copy;
  }

  return value;
}
