```js
/**
 * Normalizes a user-entered phone number to an E.164-like format:
 *   +<countryCode><nationalNumber>[x<extension>]
 *
 * Assumptions:
 * - Output format is `+` followed by digits, optionally suffixed with `x<digits>` for extensions.
 * - `defaultCountry` is a dialing code string or number such as `1`, `44`, or `33`.
 * - If `input` starts with `+`, that country code is preserved.
 * - If `input` starts with `00`, it is treated as an international prefix and converted to `+`.
 * - Otherwise, the number is treated as local and `defaultCountry` is prepended.
 * - Common formatting punctuation and whitespace are ignored.
 * - Extensions are recognized via `ext`, `ext.`, or `x` followed by digits.
 * - Alphabetic characters in the main number are rejected; this does not support vanity numbers like 1-800-FLOWERS.
 * - Empty, malformed, or digit-free input throws an Error.
 */
function normalizePhoneNumber(input, defaultCountry) {
  if (input == null) {
    throw new Error('Phone number is required');
  }

  const raw = String(input).trim();
  if (!raw) {
    throw new Error('Phone number is required');
  }

  const country = String(defaultCountry ?? '').trim();
  if (!/^\d+$/.test(country)) {
    throw new Error('defaultCountry must be digits only');
  }

  const extMatch = raw.match(/(?:\bext\.?|\bx)\s*(\d+)\s*$/i);
  const extension = extMatch ? extMatch[1] : '';
  const withoutExtension = extMatch ? raw.slice(0, extMatch.index).trim() : raw;

  if (/[A-Za-z]/.test(withoutExtension)) {
    throw new Error('Phone number contains invalid characters');
  }

  let normalized = withoutExtension.replace(/[().\-\s]/g, '');

  if (normalized.startsWith('00')) {
    normalized = `+${normalized.slice(2)}`;
  }

  if (normalized.startsWith('+')) {
    const digits = normalized.slice(1);
