function groupAnagrams(words) {
  const groups = new Map();

  for (const word of words) {
    const key = [...word].sort((a, b) => a.localeCompare(b)).join('');
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(word);
  }

  return [...groups.values()];
}

module.exports = { groupAnagrams };
```

Case-sensitive rule: grouping **is case-sensitive**. That means `"Eat"` and `"tea"` do **not** belong in the same group because uppercase and lowercase letters are treated as different characters.

