function unflattenObject(obj) {
  const result = {};

  for (const [flatKey, value] of Object.entries(obj)) {
    if (flatKey === "") {
      throw new Error("Invalid key: key cannot be empty");
    }

    const parts = flatKey.split(".");
    if (parts.some((part) => part === "")) {
      throw new Error(`Invalid key: "${flatKey}" contains empty path segments`);
    }

    let current = result;

    for (let i = 0; i < parts.length; i++) {
      const part = parts[i];
      const isLeaf = i === parts.length - 1;

      if (isLeaf) {
        if (
          Object.prototype.hasOwnProperty.call(current, part) &&
          current[part] !== null &&
          typeof current[part] === "object"
        ) {
          throw new Error(`Conflicting path: "${flatKey}" conflicts with an existing nested object`);
        }
        current[part] = value;
        continue;
      }

      if (!Object.prototype.hasOwnProperty.call(current, part)) {
        current[part] = {};
      } else if (current[part] === null || typeof current[part] !== "object") {
        throw new Error(`Conflicting path: "${flatKey}" conflicts at "${parts.slice(0, i + 1).join(".")}"`);
      }

      current = current[part];
    }
  }

  return result;
}
