```js
function parseCsvLine(line) {
  if (typeof line !== 'string') {
    throw new TypeError('parseCsvLine expects a string');
  }

  if (line === '') {
    return [''];
  }

  const fields = [];
  let field = '';
  let inQuotes = false;
  let wasQuoted = false;

  for (let i = 0; i < line.length; i += 1) {
    const ch = line[i];

    if (inQuotes) {
      if (ch === '"') {
        if (line[i + 1] === '"') {
          field += '"';
          i += 1;
        } else {
          inQuotes = false;
          wasQuoted = true;
        }
      } else {
        field += ch;
      }
      continue;
    }

    if (ch === ',') {
      fields.push(field);
      field = '';
      wasQuoted = false;
      continue;
    }

    if (ch === '"') {
      if (field.length === 0) {
        inQuotes = true;
        continue;
      }
      throw new Error(`Malformed CSV: unexpected quote at index ${i}`);
    }

    if (wasQuoted) {
      throw new Error(`Malformed CSV: unexpected character after closing quote at index ${i}`);
    }

    field += ch;
  }

  if (inQuotes) {
    throw new Error('Malformed CSV: unmatched quote');
  }

  fields.push(field);
  return fields;
}

module.exports = { parseCsvLine };
```

