function toTitleCase(input) {
  if (typeof input !== 'string' || input.length === 0) return '';

  let result = '';
  let startOfWord = true;

  for (let i = 0; i < input.length; i++) {
    const char = input[i];
    const isLetter = /[A-Za-z]/.test(char);
    const isDigit = /[0-9]/.test(char);

    if (isLetter) {
      result += startOfWord ? char.toUpperCase() : char.toLowerCase();
      startOfWord = false;
    } else {
      result += char;

      if (char === "'" && i > 0 && /[A-Za-z]/.test(input[i - 1])) {
        startOfWord = false;
      } else {
        startOfWord = !isDigit;
      }
    }
  }

  return result;
}

module.exports = { toTitleCase };
