      nums: [1, 2, 3, 4, 5],
      target: 6,
      expected: [-1, -1],
    },
    {
      name: 'all values equal to target',
      nums: [7, 7, 7, 7],
      target: 7,
      expected: [0, 3],
    },
    {
      name: 'empty array',
      nums: [],
      target: 1,
      expected: [-1, -1],
    },
    {
      name: 'single-element hit',
      nums: [4],
      target: 4,
      expected: [0, 0],
    },
    {
      name: 'single-element miss',
      nums: [4],
      target: 2,
      expected: [-1, -1],
    },
    {
      name: 'duplicates at start',
      nums: [2, 2, 2, 3, 4, 5],
      target: 2,
      expected: [0, 2],
    },
    {
      name: 'duplicates at end',
      nums: [1, 2, 3, 5, 5, 5],
