function memoize(fn) {
  if (typeof fn !== 'function') {
    throw new TypeError('memoize expects a function');
  }

  const root = new Map();
  const RESULT = Symbol('result');
  const ERROR = Symbol('error');

  function getChildNode(node, arg) {
    const isObjectKey = (arg !== null && (typeof arg === 'object' || typeof arg === 'function'));
    const mapKey = isObjectKey ? 'object' : 'primitive';

    let bucket = node.get(mapKey);
    if (!bucket) {
      bucket = isObjectKey ? new WeakMap() : new Map();
      node.set(mapKey, bucket);
    }

    let child = bucket.get(arg);
    if (!child) {
      child = new Map();
      bucket.set(arg, child);
    }

    return child;
  }

  return function memoized(...args) {
    let node = root;

    for (const arg of args) {
      node = getChildNode(node, arg);
    }

    if (node.has(RESULT)) {
      return node.get(RESULT);
    }

    if (node.has(ERROR)) {
      throw node.get(ERROR);
    }

    try {
      const value = fn.apply(this, args);
      node.set(RESULT, value);
      return value;
    } catch (error) {
      node.set(ERROR, error);
      throw error;
    }
  };
}
