function diffArrays(a, b) {
  if (!Array.isArray(a) || !Array.isArray(b)) {
    throw new TypeError('diffArrays expects two arrays');
  }

  const countsA = new Map();
  const countsB = new Map();

  for (const item of a) {
    countsA.set(item, (countsA.get(item) || 0) + 1);
  }

  for (const item of b) {
    countsB.set(item, (countsB.get(item) || 0) + 1);
  }

  const allValues = new Set([...countsA.keys(), ...countsB.keys()]);
  const added = [];
  const removed = [];
  const unchanged = [];

  for (const value of allValues) {
    const countA = countsA.get(value) || 0;
    const countB = countsB.get(value) || 0;
    const shared = Math.min(countA, countB);

    for (let i = 0; i < shared; i++) unchanged.push(value);
    for (let i = 0; i < countB - shared; i++) added.push(value);
    for (let i = 0; i < countA - shared; i++) removed.push(value);
  }

  return { added, removed, unchanged };
}
```

Multiplicity matters: values are compared as a multiset, so duplicates are counted. If a value appears twice in `a` and three times in `b`, one instance is `added` and two are `unchanged`.

