function humanFileSize(bytes) {
  if (typeof bytes !== 'number' || !Number.isFinite(bytes)) {
    throw new TypeError('bytes must be a finite number');
  }

  const base = 1024;
  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB'];
  const sign = bytes < 0 ? '-' : '';
  const abs = Math.abs(bytes);

  if (abs === 0) return '0 B';

  let unitIndex = 0;
  let value = abs;

  while (value >= base && unitIndex < units.length - 1) {
    value /= base;
    unitIndex++;
  }

  const rounded = value >= 10 || Number.isInteger(value)
    ? Math.round(value * 10) / 10
    : Math.round(value * 100) / 100;

  return `${sign}${Number(rounded.toFixed(rounded < 10 && !Number.isInteger(rounded) ? 2 : 1)).toString()} ${units[unitIndex]}`;
}

module.exports = { humanFileSize };
```

