function wordWrap(text, maxWidth) {
  if (!Number.isInteger(maxWidth) || maxWidth < 1) {
    throw new TypeError('maxWidth must be a positive integer');
  }
  if (text === '') return '';

  const lines = String(text).split('\n');

  return lines
    .map((line) => wrapSingleLine(line, maxWidth))
    .join('\n');
}

function wrapSingleLine(line, maxWidth) {
  const tokens = line.match(/\S+|\s+/g) || [];
  const out = [];
  let current = '';

  for (const token of tokens) {
    if (/^\s+$/.test(token)) {
      if (current !== '') {
        current += token;
      }
      continue;
    }

    if (current === '') {
      pushWord(token, maxWidth, out, value => {
        current = value;
      });
      continue;
    }

    if ((current + token).length <= maxWidth) {
      current += token;
      continue;
    }

    out.push(trimTrailingSpaces(current));
    current = '';
    pushWord(token, maxWidth, out, value => {
      current = value;
    });
  }

  if (current !== '') {
    out.push(trimTrailingSpaces(current));
  }

  return out.join('\n');
}

function pushWord(word, maxWidth, out, setCurrent) {
  if (word.length <= maxWidth) {
    setCurrent(word);
    return;
  }

  for (let i = 0; i < word.length; i += maxWidth) {
    const chunk = word.slice(i, i + maxWidth);
    if (chunk.length === maxWidth) {
      out.push(chunk);
    } else {
      setCurrent(chunk);
    }
  }
}

function trimTrailingSpaces(value) {
  return value.replace(/[ \t]+$/g, '');
}

module.exports = { wordWrap };
```

