```js
function unescapeHtml(input) {
  if (input === '') return '';

  const namedEntities = {
    amp: '&',
    lt: '<',
    gt: '>',
    quot: '"',
    apos: "'",
    nbsp: '\u00A0',
  };

  return input.replace(/&(#x[0-9a-fA-F]+|#\d+|[a-zA-Z][a-zA-Z0-9]+);/g, (match, entity) => {
    if (entity[0] === '#') {
      const isHex = entity[1].toLowerCase() === 'x';
      const value = isHex ? parseInt(entity.slice(2), 16) : parseInt(entity.slice(1), 10);

      if (!Number.isFinite(value) || value < 0 || value > 0x10ffff) {
        return match;
      }

      try {
        return String.fromCodePoint(value);
      } catch {
        return match;
      }
    }

    return Object.prototype.hasOwnProperty.call(namedEntities, entity)
      ? namedEntities[entity]
      : match;
  });
}
