```js
function buildTree(items) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  const nodes = new Map();
  const parentById = new Map();

  for (let i = 0; i < items.length; i++) {
    const item = items[i];

    if (!item || typeof item !== 'object' || Array.isArray(item)) {
      throw new TypeError(`items[${i}] must be an object`);
    }

    const { id, parentId } = item;

    if (id === undefined || id === null) {
      throw new Error(`items[${i}].id is required`);
    }

    if (nodes.has(id)) {
      throw new Error(`Duplicate id: ${id}`);
    }

    nodes.set(id, { ...item, children: [] });
    parentById.set(id, parentId ?? null);
  }

  for (const [id, parentId] of parentById) {
    if (parentId === null) continue;

    if (!nodes.has(parentId)) {
      throw new Error(`Missing parent: ${parentId} for node ${id}`);
    }

    if (parentId === id) {
      throw new Error(`Cycle detected at node ${id}`);
    }
  }

  const visitState = new Map();

  function detectCycle(id, path = []) {
    const state = visitState.get(id);
    if (state === 1) {
      throw new Error(`Cycle detected: ${[...path, id].join(' -> ')}`);
    }
    if (state === 2) return;

    visitState.set(id, 1);
    const parentId = parentById.get(id);
    if (parentId !== null) {
      detectCycle(parentId, [...path, id]);
    }
    visitState.set(id, 2);
  }

  for (const id of nodes.keys()) {
    detectCycle(id);
  }

  const roots = [];

  for (const [id, node] of nodes) {
    const parentId = parentById.get(id);
    if (parentId === null) {
      roots.push(node);
    } else {
      nodes.get(parentId).children.push(node);
    }
  }

  return roots;
}

module.exports = { buildTree };
```

