function relativePath(from, to) {
  if (typeof from !== 'string' || typeof to !== 'string') {
    throw new TypeError('relativePath expects two string paths');
  }

  const hasBackslash = from.includes('\\') || to.includes('\\');
  const separator = hasBackslash ? '\\' : '/';
  const isAbsolute = (path) => {
    if (separator === '\\') {
      return /^[A-Za-z]:\\|^\\\\/.test(path);
    }
    return path.startsWith('/');
  };

  if (!isAbsolute(from) || !isAbsolute(to)) {
    throw new Error('relativePath expects absolute paths');
  }

  const normalize = (path) => {
    let normalized = path.replace(/[\\/]+/g, separator);

    if (separator === '/') {
      if (normalized.length > 1) normalized = normalized.replace(/\/+$/g, '');
      const parts = normalized.split('/').filter(Boolean);
      return { root: '/', parts };
    }

    const uncMatch = normalized.match(/^\\\\[^\\]+\\[^\\]+/);
    if (uncMatch) {
      const root = uncMatch[0];
      let rest = normalized.slice(root.length).replace(/^\\+/, '');
      if (rest) rest = rest.replace(/\\+$/g, '');
      return { root, parts: rest ? rest.split('\\').filter(Boolean) : [] };
    }

    const driveMatch = normalized.match(/^[A-Za-z]:/);
    if (!driveMatch) {
      throw new Error('Unsupported absolute path format');
    }

    const root = driveMatch[0] + '\\';
    let rest = normalized.slice(root.length).replace(/^\\+/, '');
    if (rest) rest = rest.replace(/\\+$/g, '');
    return { root, parts: rest ? rest.split('\\').filter(Boolean) : [] };
  };

  const a = normalize(from);
  const b = normalize(to);

  const sameRoot = separator === '/'
    ? a.root === b.root
    : a.root.toLowerCase() === b.root.toLowerCase();

  if (!sameRoot) {
    throw new Error('Cannot compute relative path across different roots');
  }

  let i = 0;
  while (
    i < a.parts.length &&
    i < b.parts.length &&
    (separator === '/'
      ? a.parts[i] === b.parts[i]
      : a.parts[i].toLowerCase() === b.parts[i].toLowerCase())
  ) {
    i += 1;
  }

  const up = new Array(a.parts.length - i).fill('..');
  const down = b.parts.slice(i);
  const result = [...up, ...down].join(separator);

  return result || '.';
}

module.exports = { relativePath };
