```js
/**
 * Sort an array of objects by multiple keys and directions.
 *
 * Assumptions:
 * - `rules` is an array of objects like: `{ key: 'name', direction: 'asc' }`.
 * - `direction` defaults to `'asc'`.
 * - Missing fields (`undefined` or `null`) sort after present values in ascending order
 *   and before present values in descending order.
 * - Mixed primitive types are compared with this precedence when types differ:
 *   `number < bigint < string < boolean < symbol < other`.
 * - String values are compared with `localeCompare`.
 * - Sorting is stable: if all rules consider two items equal, original order is preserved.
 * - The function does not mutate the input array.
 */
function sortByMultiple(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  if (!Array.isArray(rules)) {
    throw new TypeError('rules must be an array');
  }

  if (items.length <= 1 || rules.length === 0) {
    return items.slice();
  }

  const typeRank = (value) => {
    const t = typeof value;
    switch (t) {
      case 'number': return 0;
      case 'bigint': return 1;
      case 'string': return 2;
      case 'boolean': return 3;
      case 'symbol': return 4;
      default: return 5;
    }
  };

  const compareValues = (a, b) => {
    const aMissing = a == null;
    const bMissing = b == null;

    if (aMissing && bMissing) return 0;
    if (aMissing) return 1;
    if (bMissing) return -1;

    const aType = typeof a;
    const bType = typeof b;

    if (aType !== bType) {
      return typeRank(a) - typeRank(b);
    }

    if (aType === 'string') return a.localeCompare(b);
    if (aType === 'number') {
      if (Number.isNaN(a) && Number.isNaN(b)) return 0;
      if (Number.isNaN(a)) return 1;
      if (Number.isNaN(b)) return -1;
      return a - b;
    }
    if (aType === 'bigint') return a < b ? -1 : a > b ? 1 : 0;
    if (aType === 'boolean') return a === b ? 0 : a ? 1 : -1;
    if (aType === 'symbol') return String(a).localeCompare(String(b));

    const aStr = String(a);
    const bStr = String(b);
    return aStr.localeCompare(bStr);
  };

  return items
    .map((item, index) => ({ item, index }))
    .sort((left, right) => {
      for (const rule of rules) {
        if (!rule || typeof rule.key !== 'string' || rule.key.length === 0) {
          continue;
        }

        const direction = rule.direction === 'desc' ? -1 : 1;
        const result = compareValues(left.item[rule.key], right.item[rule.key]);

        if (result !== 0) {
          return result * direction;
        }
      }

      return left.index - right.index;
    })
    .map(({ item }) => item);
}

module.exports = { sortByMultiple };
```

