function transposeCsv(rows) {
  if (!Array.isArray(rows)) {
    throw new TypeError('transposeCsv expects an array of rows');
  }

  if (rows.length === 0) {
    return [];
  }

  let maxColumns = 0;
  for (const row of rows) {
    if (!Array.isArray(row)) {
      throw new TypeError('transposeCsv expects each row to be an array');
    }
    if (row.length > maxColumns) {
      maxColumns = row.length;
    }
  }

  const result = [];
  for (let col = 0; col < maxColumns; col++) {
    const transposedRow = [];
    for (let rowIndex = 0; rowIndex < rows.length; rowIndex++) {
      const value = rows[rowIndex][col];
      transposedRow.push(typeof value === 'string' ? value : '');
    }
    result.push(transposedRow);
  }

  return result;
}

module.exports = { transposeCsv };
```

