```js
function minWindowSubstring(text, pattern) {
  if (pattern.length === 0) return "";
  if (text.length === 0 || pattern.length > text.length) return "";

  const need = new Map();
  for (const ch of pattern) {
    need.set(ch, (need.get(ch) || 0) + 1);
  }

  let missing = pattern.length;
  let left = 0;
  let bestStart = 0;
  let bestLen = Infinity;

  for (let right = 0; right < text.length; right++) {
    const ch = text[right];
    if (need.has(ch)) {
      const count = need.get(ch);
      if (count > 0) missing--;
      need.set(ch, count - 1);
    }

    while (missing === 0) {
      const windowLen = right - left + 1;
      if (windowLen < bestLen) {
        bestLen = windowLen;
        bestStart = left;
      }

      const leftChar = text[left];
      if (need.has(leftChar)) {
        const count = need.get(leftChar);
        need.set(leftChar, count + 1);
        if (count + 1 > 0) missing++;
      }
      left++;
    }
  }

  return bestLen === Infinity ? "" : text.slice(bestStart, bestStart + bestLen);
}

// Tests
function runTests() {
  const cases = [
    {
      name: "basic example",
      text: "ADOBECODEBANC",
      pattern: "ABC",
      expected: "BANC",
    },
    {
      name: "no match",
      text: "hello",
      pattern: "world",
      expected: "",
    },
    {
      name: "exact match",
      text: "ABC",
      pattern: "ABC",
      expected: "ABC",
    },
    {
      name: "repeated characters in pattern",
      text: "AAABBC",
      pattern: "AABC",
      expected: "AABBC",
    },
    {
      name: "empty text",
      text: "",
      pattern: "ABC",
      expected: "",
    },
    {
      name: "empty pattern",
      text: "ABC",
      pattern: "",
      expected: "",
    },
    {
      name: "case sensitivity",
      text: "aAaBbBc",
      pattern: "ABc",
      expected: "AaBbBc",
    },
    {
      name: "multiple valid windows picks smallest",
      text: "abdecfabbaac",
      pattern: "abc",
      expected: "bac",
    },
    {
      name: "pattern longer than text",
      text: "AB",
      pattern: "ABC",
      expected: "",
    },
    {
      name: "single character match",
      text: "xyz",
      pattern: "y",
      expected: "y",
    },
  ];

  for (const { name, text, pattern, expected } of cases) {
    const actual = minWindowSubstring(text, pattern);
    if (actual !== expected) {
      throw new Error(
        `${name} failed: expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`
      );
    }
  }

  console.log(`Passed ${cases.length} tests.`);
}

runTests();
```

This runs in **O(n + m)** time and uses **O(k)** space, where `k` is the number of distinct characters in `pattern`.

