const assert = require('assert');
const { detectCycle } = require('./detectCycle');

function ListNode(val) {
  this.val = val;
  this.next = null;
}

function buildList(values) {
  if (values.length === 0) return { head: null, nodes: [] };

  const nodes = values.map((v) => new ListNode(v));
  for (let i = 0; i < nodes.length - 1; i++) {
    nodes[i].next = nodes[i + 1];
  }

  return { head: nodes[0], nodes };
}

(function runTests() {
  // 1. empty list
  assert.strictEqual(detectCycle(null), false);

  // 2. one node without cycle
  {
    const node = new ListNode(1);
    assert.strictEqual(detectCycle(node), false);
  }

  // 3. one node with self-cycle
  {
    const node = new ListNode(1);
    node.next = node;
    assert.strictEqual(detectCycle(node), true);
  }

  // 4. no cycle
  {
    const { head } = buildList([1, 2, 3, 4]);
    assert.strictEqual(detectCycle(head), false);
  }

  // 5. cycle to head
  {
    const { head, nodes } = buildList([1, 2, 3, 4]);
    nodes[3].next = head;
    assert.strictEqual(detectCycle(head), true);
  }

  // 6. cycle in middle
  {
