function nearestPalindrome(n) {
  if (typeof n !== 'string' || !/^[0-9]+$/.test(n) || n.length === 0) {
    throw new TypeError('Input must be a non-empty string of digits');
  }

  if (n === '0') {
    throw new RangeError('Input must represent a positive integer');
  }

  if (n.length === 1) {
    return String(Number(n) - 1);
  }

  const len = n.length;
  const prefixLen = Math.ceil(len / 2);
  const prefix = BigInt(n.slice(0, prefixLen));
  const original = BigInt(n);

  const mirror = (leftStr, oddLength) => {
    const right = leftStr
      .slice(0, oddLength ? -1 : leftStr.length)
      .split('')
      .reverse()
      .join('');
    return leftStr + right;
  };

  const candidates = new Set([
    '9'.repeat(len - 1) || '0',
    '1' + '0'.repeat(len - 1) + '1',
  ]);

  for (const delta of [-1n, 0n, 1n]) {
    const next = prefix + delta;
    if (next < 0n) continue;
    candidates.add(mirror(next.toString(), len % 2 === 1));
  }

  candidates.delete(n);

  let best = null;
  let bestDiff = null;

  for (const candidate of candidates) {
    if (!/^(0|[1-9][0-9]*)$/.test(candidate)) continue;

    const value = BigInt(candidate);
    const diff = value >= original ? value - original : original - value;

    if (
      best === null ||
      diff < bestDiff ||
      (diff === bestDiff && value < BigInt(best))
    ) {
      best = candidate;
      bestDiff = diff;
    }
  }

  return best;
}

