```js
function removeComments(code) {
  let result = '';
  let i = 0;
  let state = 'code';
  let stringQuote = '';

  while (i < code.length) {
    const ch = code[i];
    const next = code[i + 1];

    if (state === 'line-comment') {
      if (ch === '\n') {
        result += ch;
        state = 'code';
      }
      i += 1;
      continue;
    }

    if (state === 'block-comment') {
      if (ch === '*' && next === '/') {
        state = 'code';
        i += 2;
        continue;
      }
      i += 1;
      continue;
    }

    if (state === 'string') {
      result += ch;

      if (ch === '\\') {
        if (i + 1 < code.length) {
          result += code[i + 1];
          i += 2;
          continue;
        }
      } else if (ch === stringQuote) {
        state = 'code';
        stringQuote = '';
      }

      i += 1;
      continue;
    }

    if (ch === '"' || ch === "'") {
      state = 'string';
      stringQuote = ch;
      result += ch;
      i += 1;
      continue;
    }

    if (ch === '/' && next === '/') {
      state = 'line-comment';
      i += 2;
      continue;
    }

    if (ch === '/' && next === '*') {
      state = 'block-comment';
      i += 2;
      continue;
    }

    result += ch;
    i += 1;
  }

  return result;
}

module.exports = { removeComments };
```

