function romanToInt(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Roman numeral must be a string');
  }

  const valueMap = {
    I: 1,
    V: 5,
    X: 10,
    L: 50,
    C: 100,
    D: 500,
    M: 1000,
  };

  const subtractives = new Set(['IV', 'IX', 'XL', 'XC', 'CD', 'CM']);
  const nonRepeatable = new Set(['V', 'L', 'D']);

  const s = input.trim().toUpperCase();

  if (s.length === 0) {
    throw new Error('Roman numeral must not be empty');
  }

  if (!/^[IVXLCDM]+$/.test(s)) {
    throw new Error('Roman numeral contains invalid characters');
  }

  let total = 0;
  let i = 0;
  let repeatCount = 1;

  while (i < s.length) {
    const current = s[i];
    const currentValue = valueMap[current];
    const next = s[i + 1];
    const nextValue = next ? valueMap[next] : 0;

    if (i > 0) {
      if (s[i] === s[i - 1]) {
        repeatCount += 1;
        if (nonRepeatable.has(current)) {
          throw new Error(`Symbol ${current} cannot repeat`);
        }
        if (repeatCount > 3) {
          throw new Error(`Symbol ${current} repeated too many times`);
        }
      } else {
        repeatCount = 1;
      }
    }

    if (next && currentValue < nextValue) {
      const pair = current + next;

      if (!subtractives.has(pair)) {
        throw new Error(`Invalid subtractive pair: ${pair}`);
      }

      if (repeatCount > 1) {
        throw new Error(`Invalid repetition before subtractive pair: ${pair}`);
      }

      total += nextValue - currentValue;
      i += 2;
      repeatCount = 1;
      continue;
    }

    total += currentValue;
    i += 1;
  }

  const canonical = intToRoman(total);
  if (canonical !== s) {
    throw new Error('Malformed Roman numeral');
  }

  return total;
}

function intToRoman(num) {
  if (!Number.isInteger(num) || num <= 0 || num > 3999) {
    throw new Error('Roman numeral value out of range');
  }

  const table = [
    ['M', 1000],
    ['CM', 900],
    ['D', 500],
    ['CD', 400],
    ['C', 100],
    ['XC', 90],
    ['L', 50],
    ['XL', 40],
    ['X', 10],
    ['IX', 9],
    ['V', 5],
    ['IV', 4],
    ['I', 1],
  ];

  let remaining = num;
  let result = '';

  for (const [symbol, value] of table) {
    while (remaining >= value) {
      result += symbol;
      remaining -= value;
    }
  }

  return result;
}

module.exports = { romanToInt };
```

