**Encryption vs. hashing**
- **Encryption** is **reversible** with the right key. You use it when you need to recover the original plaintext later.
- **Hashing** is designed to be **one-way**. You use it to verify integrity or store password-derived values, not to get the original input back.
- Encryption output can be decrypted; hash output cannot realistically be reversed.
- Encryption typically uses a **secret key**; hashing uses a **hash function** and may also use a **salt** for password storage.

Here’s a simple **Node.js** example using **AES-256-CBC** to encrypt and decrypt a string:

```js
const crypto = require('crypto');

const algorithm = 'aes-256-cbc';
const key = crypto.randomBytes(32); // 32 bytes for AES-256
const iv = crypto.randomBytes(16);  // 16 bytes for CBC IV

function encrypt(text) {
  const cipher = crypto.createCipheriv(algorithm, key, iv);
  let encrypted = cipher.update(text, 'utf8', 'hex');
  encrypted += cipher.final('hex');
  return encrypted;
}

function decrypt(encryptedText) {
  const decipher = crypto.createDecipheriv(algorithm, key, iv);
  let decrypted = decipher.update(encryptedText, 'hex', 'utf8');
  decrypted += decipher.final('utf8');
  return decrypted;
}

const plaintext = 'Hello, AES encryption!';
const encrypted = encrypt(plaintext);
const decrypted = decrypt(encrypted);

console.log('Plaintext:', plaintext);
console.log('Encrypted:', encrypted);
console.log('Decrypted:', decrypted);
```

