Markdown headings use `#` prefixes: `#` for level 1, `##` for level 2, through `######` for level 6. A heading’s level determines its place in the document hierarchy, so a table of contents can be built by nesting each heading under the nearest earlier heading with a smaller level.
```js
function parseMarkdownToc(markdown) {
  const lines = markdown.split(/\r?\n/);
  const root = [];
  const stack = [];

  for (const line of lines) {
    const match = line.match(/^(#{1,6})\s+(.+?)\s*#*\s*$/);
    if (!match) continue;

    const level = match[1].length;
    const title = match[2].trim();
    const node = { title, level, children: [] };

    while (stack.length && stack[stack.length - 1].level >= level) {
      stack.pop();
    }

    if (stack.length === 0) {
      root.push(node);
    } else {
      stack[stack.length - 1].children.push(node);
    }

    stack.push(node);
  }

  return root;
}
```

Example:

```js
const md = `
# Title
## Intro
### Details
## Usage
# API
### Methods
`;

console.log(JSON.stringify(parseMarkdownToc(md), null, 2));
