      const rawBody = (req as any).rawBody as Buffer | undefined;
      if (!rawBody) {
        return res.status(400).json({ error: 'Missing raw body' });
      }

      const headerValue = req.header(headerName);
      if (!headerValue) {
        return res.status(401).json({ error: 'Missing signature header' });
      }

      const parsed = parseSignatureHeader(headerValue);
      if (!parsed.timestamp || parsed.signatures.length === 0) {
        return res.status(401).json({ error: 'Malformed signature header' });
      }

      const now = Math.floor(Date.now() / 1000);
      if (Math.abs(now - parsed.timestamp) > maxSkewSeconds) {
        return res.status(401).json({ error: 'Expired signature timestamp' });
      }

      if (options.replayCache && parsed.eventId) {
        const seen = await options.replayCache.has(parsed.eventId);
        if (seen) {
          return res.status(409).json({ error: 'Replay detected' });
        }
      }

      const secret = await options.secretResolver(parsed.keyId);
      if (!secret) {
        return res.status(401).json({ error: 'Unknown webhook key' });
      }

      const payload = `${parsed.timestamp}.${rawBody.toString('utf8')}`;
      const expected = crypto.createHmac('sha256', secret).update(payload).digest('hex');

      const valid = parsed.signatures.some(sig => timingSafeEqualHex(sig, expected));
      if (!valid) {
        return res.status(401).json({ error: 'Invalid signature' });
      }

      if (options.replayCache && parsed.eventId) {
        await options.replayCache.set(parsed.eventId, maxSkewSeconds);
      }

      (req as any).webhook = {
        verified: true,
        timestamp: parsed.timestamp,
        keyId: parsed.keyId,
        eventId: parsed.eventId,
      };

      next();
    } catch {
      res.status(500).json({ error: 'Verification failure' });
    }
  };
}

function parseSignatureHeader(header: string): ParsedSignature {
  const parts = header.split(',').map(p => p.trim());
  const out: ParsedSignature = { timestamp: 0, signatures: [] };

  for (const part of parts) {
    const [k, v] = part.split('=', 2);
    if (!k || !v) continue;
    if (k === 't') out.timestamp = Number(v);
    if (k === 'v1') out.signatures.push(v);
    if (k === 'kid') out.keyId = v;
    if (k === 'id') out.eventId = v;
  }

  return out;
}

function timingSafeEqualHex(a: string, b: string): boolean {
  if (!/^[a-fA-F0-9]+$/.test(a) || !/^[a-fA-F0-9]+$/.test(b)) return false;
  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(Buffer.from(a, 'hex'), Buffer.from(b, 'hex'));
}
```

**Recommended design**
- Use the raw request body, never a re-serialized JSON body.
- Sign `timestamp + "." + raw_body` with `HMAC-SHA256`.
- Include `t`, `v1`, optional `kid`, and optional event `id` in the signature header.
- Reject requests outside a short clock-skew window.
- Store event IDs briefly to block replay attacks.
- Resolve secrets by key ID to support rotation.
- Verify before parsing business payloads.

**Example header**
```text
X-Webhook-Signature: t=1711738442,v1=abc123...,kid=primary,id=evt_123
```

**Operational notes**
- Put this behind HTTPS only.
- Keep secrets in a secret manager, not env files if avoidable.
- Log verification failures without logging raw secrets or full payloads.
- Support multiple active secrets during key rotation.
- Return 2xx only after verification succeeds.

