770.answer:
A union-find (disjoint set) structure tracks a partition of elements into disjoint groups and supports two fast operations:

- **find(x)**: return the representative/root of the set containing `x`
- **union(a, b)**: merge the sets containing `a` and `b`

It’s useful for connectivity problems like Kruskal’s MST, grouping connected components, and dynamic equivalence checks.

### Core idea
Each set is stored as a tree:
- Every element points to a parent
- A root points to itself
- The root is the set representative

### Optimizations
- **Path compression** in `find(x)`: after finding the root, make nodes on the path point directly to it
- **Union by rank** in `union(a, b)`: attach the shorter tree under the taller one to keep trees shallow

Together, these make operations effectively constant time in practice: amortized **O(α(n))**, where `α` is the inverse Ackermann function.

## JavaScript implementation

```js
class UnionFind {
  constructor(n) {
    this.parent = Array.from({ length: n }, (_, i) => i);
    this.rank = Array(n).fill(0);
    this.count = n;
  }

  find(x) {
    if (this.parent[x] !== x) {
      this.parent[x] = this.find(this.parent[x]);
    }
    return this.parent[x];
  }

  union(a, b) {
    let rootA = this.find(a);
    let rootB = this.find(b);

    if (rootA === rootB) {
      return false;
    }

    if (this.rank[rootA] < this.rank[rootB]) {
      this.parent[rootA] = rootB;
    } else if (this.rank[rootA] > this.rank[rootB]) {
      this.parent[rootB] = rootA;
    } else {
      this.parent[rootB] = rootA;
      this.rank[rootA] += 1;
    }

    this.count -= 1;
    return true;
  }

  connected(a, b) {
    return this.find(a) === this.find(b);
  }

  getSetCount() {
    return this.count;
  }
}
```

## Example

```js
const uf = new UnionFind(5);

uf.union(0, 1);
uf.union(1, 2);
uf.union(3, 4);

console.log(uf.connected(0, 2)); // true
console.log(uf.connected(0, 4)); // false
console.log(uf.getSetCount());   // 2
```

## Complexity
- `find`: amortized nearly **O(1)**
- `union`: amortized nearly **O(1)**
- Space: **O(n)**

If you want, I can also give you a version that supports arbitrary keys like strings instead of only `0..n-1`.

772.answer:
Prim’s algorithm grows a minimum spanning tree (MST) one vertex at a time by always choosing the cheapest edge that connects the current tree to a new vertex.

### How it works
1. Start from any vertex.
2. Mark it as part of the MST.
3. Push all outgoing edges into a min-priority queue.
4. Repeatedly extract the smallest edge:
   - If it leads to a vertex already in the MST, skip it.
   - Otherwise, add that vertex to the MST, add the edge weight to the answer, and push that vertex’s outgoing edges.
5. Continue until all vertices are included.

This greedy choice is correct because at every step it picks the lightest edge crossing the cut between visited and unvisited vertices.

### Complexity
With an adjacency list and heap-based priority queue:
- **Time:** `O((V + E) log V)`
- **Space:** `O(V + E)`

### Go implementation
```go
package main

import (
	"container/heap"
	"fmt"
)

type Edge struct {
	to     int
	weight int
}

type Item struct {
	vertex int
	weight int
}

type PriorityQueue []Item

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].weight < pq[j].weight
}
func (pq PriorityQueue) Swap(i, j int) { pq[i], pq[j] = pq[j], pq[i] }

func (pq *PriorityQueue) Push(x any) {
	*pq = append(*pq, x.(Item))
}

func (pq *PriorityQueue) Pop() any {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[:n-1]
	return item
}

// primMST returns the total weight of the minimum spanning tree.
// If the graph is disconnected, it returns -1.
func primMST(n int, graph [][]Edge) int {
	if n == 0 {
		return 0
	}

	visited := make([]bool, n)
	pq := &PriorityQueue{}
	heap.Init(pq)

	// Start from vertex 0 with cost 0.
	heap.Push(pq, Item{vertex: 0, weight: 0})

	totalWeight := 0
	visitedCount := 0

	for pq.Len() > 0 && visitedCount < n {
		item := heap.Pop(pq).(Item)
		v := item.vertex

		if visited[v] {
			continue
		}

		visited[v] = true
		visitedCount++
		totalWeight += item.weight

		for _, edge := range graph[v] {
			if !visited[edge.to] {
				heap.Push(pq, Item{vertex: edge.to, weight: edge.weight})
			}
		}
	}

	if visitedCount != n {
		return -1
	}

	return totalWeight
}

func main() {
	n := 5
	graph := make([][]Edge, n)

	addEdge := func(u, v, w int) {
		graph[u] = append(graph[u], Edge{to: v, weight: w})
		graph[v] = append(graph[v], Edge{to: u, weight: w})
	}

	addEdge(0, 1, 2)
	addEdge(0, 3, 6)
	addEdge(1, 2, 3)
	addEdge(1, 3, 8)
	addEdge(1, 4, 5)
	addEdge(2, 4, 7)
	addEdge(3, 4, 9)

	fmt.Println(primMST(n, graph)) // Output: 16
}
```

### Note
This version stores candidate edges implicitly as `(vertex, weight)` in the heap. That’s enough when you only need the **total MST weight**. If you also want the actual MST edges, store the parent vertex in each heap item too.

773.answer:
Topological sorting orders the vertices of a **directed acyclic graph (DAG)** so that for every edge `u -> v`, `u` appears before `v`. It’s useful for scheduling tasks with prerequisites, build systems, and dependency resolution.

### Key idea
If task `B` depends on `A`, then `A` must come before `B`. A topological sort produces one valid order that respects all such constraints.

### When it works
- **Works:** only for directed graphs with **no cycles**
- **Fails:** if there is a cycle, because no ordering can satisfy all dependencies

### Kahn’s algorithm
Kahn’s algorithm uses **in-degrees**:
- `inDegree[x]` = number of prerequisites of `x`
- Start with all nodes whose in-degree is `0`
- Repeatedly:
  1. remove one such node
  2. add it to the result
  3. reduce in-degree of its neighbors
  4. if any neighbor becomes `0`, add it to the queue
- If you process all nodes, the result is a valid topological order
- If not, a cycle exists

### Java implementation
```java
import java.util.*;

public class TopologicalSort {
    /**
     * Returns a valid topological ordering of tasks.
     *
     * @param numTasks total number of tasks labeled 0..numTasks-1
     * @param dependencies each pair [a, b] means: b must be done before a (b -> a)
     * @return a valid ordering, or an empty list if a cycle exists
     */
    public static List<Integer> kahnTopologicalSort(int numTasks, int[][] dependencies) {
        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < numTasks; i++) {
            graph.add(new ArrayList<>());
        }

        int[] inDegree = new int[numTasks];

        for (int[] dep : dependencies) {
            int task = dep[0];
            int prerequisite = dep[1];
            graph.get(prerequisite).add(task);
            inDegree[task]++;
        }

        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < numTasks; i++) {
            if (inDegree[i] == 0) {
                queue.offer(i);
            }
        }

        List<Integer> order = new ArrayList<>();

        while (!queue.isEmpty()) {
            int current = queue.poll();
            order.add(current);

            for (int neighbor : graph.get(current)) {
                inDegree[neighbor]--;
                if (inDegree[neighbor] == 0) {
                    queue.offer(neighbor);
                }
            }
        }

        if (order.size() != numTasks) {
            return Collections.emptyList(); // cycle detected
        }

        return order;
    }

    public static void main(String[] args) {
        int numTasks = 6;
        int[][] dependencies = {
            {2, 5},
            {0, 5},
            {0, 4},
            {1, 4},
            {3, 2},
            {1, 3}
        };

        List<Integer> order = kahnTopologicalSort(numTasks, dependencies);

        if (order.isEmpty()) {
            System.out.println("Cycle detected. No valid ordering exists.");
        } else {
            System.out.println("Valid task order: " + order);
        }
    }
}
```

### Example interpretation
For dependency pair `[2, 5]`, task `5` must happen before task `2`.

One valid output for the sample is:
```java
[4, 5, 0, 2, 3, 1]
```
Another valid ordering may also be correct.

### Time complexity
- **O(V + E)**
- `V` = number of tasks
- `E` = number of dependencies

If you want, I can also provide:
- a version that throws an exception on cycles
- a DFS-based topological sort
- a LeetCode-style `canFinish` / `findOrder` version

775.answer:
A trie stores strings by characters along a tree, where each edge represents one character and each path from the root spells a prefix. This makes prefix-based operations efficient: time is proportional to the word length rather than the number of stored words.

For lowercase English words, each node typically has 26 children and a flag marking whether a word ends at that node.

- `Insert(word)`: walk/create nodes for each character, then mark the last node as a word end.
- `Search(word)`: walk the path; return true only if the final node exists and is marked as a complete word.
- `StartsWith(prefix)`: walk the path; return true if all prefix characters exist.

Time complexity for all three is `O(L)`, where `L` is the input length. Space depends on how many distinct prefixes are stored.

```csharp
using System;

public class Trie
{
    private class TrieNode
    {
        public TrieNode[] Children = new TrieNode[26];
        public bool IsWord;
    }

    private readonly TrieNode _root = new TrieNode();

    public void Insert(string word)
    {
        TrieNode node = _root;

        foreach (char c in word)
        {
            int index = c - 'a';
            if (node.Children[index] == null)
            {
                node.Children[index] = new TrieNode();
            }

            node = node.Children[index];
        }

        node.IsWord = true;
    }

    public bool Search(string word)
    {
        TrieNode node = Traverse(word);
        return node != null && node.IsWord;
    }

    public bool StartsWith(string prefix)
    {
        return Traverse(prefix) != null;
    }

    private TrieNode Traverse(string s)
    {
        TrieNode node = _root;

        foreach (char c in s)
        {
            int index = c - 'a';
            if (node.Children[index] == null)
            {
                return null;
            }

            node = node.Children[index];
        }

        return node;
    }
}
```

Example:

```csharp
var trie = new Trie();
trie.Insert("apple");

Console.WriteLine(trie.Search("apple"));    // true
Console.WriteLine(trie.Search("app"));      // false
Console.WriteLine(trie.StartsWith("app"));  // true

trie.Insert("app");
Console.WriteLine(trie.Search("app"));      // true
```

