A binary search tree (BST) is a binary tree where, for every node, all values in the left subtree are smaller and all values in the right subtree are larger. This ordering makes search, insert, and delete efficient on average: `O(log n)` when the tree stays reasonably balanced, but `O(n)` in the worst case if it becomes skewed.

Here’s a simple Python implementation with `insert`, `search`, and in-order traversal:

```python
class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None


class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, value):
        if self.root is None:
            self.root = Node(value)
            return

        current = self.root
        while True:
            if value < current.value:
                if current.left is None:
                    current.left = Node(value)
                    return
                current = current.left
            elif value > current.value:
                if current.right is None:
                    current.right = Node(value)
                    return
                current = current.right
            else:
                return  # ignore duplicates

    def search(self, value):
        current = self.root
        while current is not None:
            if value == current.value:
                return True
            if value < current.value:
                current = current.left
            else:
                current = current.right
        return False

    def inorder(self):
        result = []

        def traverse(node):
            if node is None:
                return
            traverse(node.left)
            result.append(node.value)
            traverse(node.right)

        traverse(self.root)
        return result


# Example usage
bst = BinarySearchTree()
for value in [8, 3, 10, 1, 6, 14, 4, 7, 13]:
    bst.insert(value)

print(bst.search(6))    # True
print(bst.search(2))    # False
print(bst.inorder())    # [1, 3, 4, 6, 7, 8, 10, 13, 14]
```

In-order traversal visits `left -> node -> right`, so in a BST it returns the values in sorted order.

If you want, I can also add a `delete` method.

