A heap is a **complete binary tree** that satisfies a priority rule.

- In a **min-heap**, every parent is `<=` its children, so the smallest value is at the root.
- In a **max-heap**, every parent is `>=` its children, so the largest value is at the root.

Using an array makes heaps efficient:
- parent of `i` is `(i - 1) / 2`
- left child is `2 * i + 1`
- right child is `2 * i + 2`

For a min-heap:
- **insert(x)**: put `x` at the end, then "bubble up" while it is smaller than its parent
- **peek()**: return the root (minimum)
- **extractMin()**: remove the root, move the last element to the root, then "bubble down"

Complexities:
- `insert`: **O(log n)**
- `extractMin`: **O(log n)**
- `peek`: **O(1)**

C++ min-heap implementation with `insert`, `peek`, and `extractMin`:

```cpp
#include <iostream>
#include <vector>
#include <stdexcept>
using namespace std;

class MinHeap {
private:
    vector<int> heap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[index] >= heap[parent]) break;
            swap(heap[index], heap[parent]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int n = heap.size();
        while (true) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int smallest = index;

            if (left < n && heap[left] < heap[smallest]) {
                smallest = left;
            }
            if (right < n && heap[right] < heap[smallest]) {
                smallest = right;
            }
            if (smallest == index) break;

            swap(heap[index], heap[smallest]);
            index = smallest;
        }
    }

public:
    void insert(int value) {
        heap.push_back(value);
        heapifyUp(heap.size() - 1);
    }

    int peek() const {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }
        return heap[0];
    }

    int extractMin() {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }

        int minValue = heap[0];
        heap[0] = heap.back();
        heap.pop_back();

        if (!heap.empty()) {
            heapifyDown(0);
        }

        return minValue;
    }

    bool empty() const {
        return heap.empty();
    }
};

int main() {
    MinHeap h;

    h.insert(10);
    h.insert(4);
    h.insert(15);
    h.insert(2);
    h.insert(8);

    cout << "Min: " << h.peek() << "\n";          // 2
    cout << h.extractMin() << "\n";                // 2
    cout << h.extractMin() << "\n";                // 4
    cout << "Min: " << h.peek() << "\n";          // 8

    return 0;
}
```

