The Template Method pattern defines the skeleton of an algorithm in a base class and lets subclasses override specific steps without changing the overall flow.

Use it when:
- the workflow is fixed
- some steps vary by implementation
- you want to avoid duplicating orchestration logic

For a data parser, the base class can control the parsing pipeline:
1. validate input
2. parse raw data
3. transform result
4. return output

The subclasses only implement the format-specific parsing logic.

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.Json;

public abstract class DataParser
{
    public List<Dictionary<string, string>> Parse(string input)
    {
        Validate(input);
        var records = ParseCore(input);
        return Transform(records);
    }

    protected virtual void Validate(string input)
    {
        if (string.IsNullOrWhiteSpace(input))
            throw new ArgumentException("Input cannot be empty.");
    }

    protected abstract List<Dictionary<string, string>> ParseCore(string input);

    protected virtual List<Dictionary<string, string>> Transform(List<Dictionary<string, string>> records)
    {
        return records;
    }
}

public sealed class CsvParser : DataParser
{
    protected override List<Dictionary<string, string>> ParseCore(string input)
    {
        var lines = input
            .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);

        if (lines.Length < 2)
            return new List<Dictionary<string, string>>();

        var headers = lines[0].Split(',').Select(h => h.Trim()).ToArray();
        var result = new List<Dictionary<string, string>>();

        for (int i = 1; i < lines.Length; i++)
        {
            var values = lines[i].Split(',').Select(v => v.Trim()).ToArray();
            var record = new Dictionary<string, string>();

            for (int j = 0; j < headers.Length; j++)
            {
                record[headers[j]] = j < values.Length ? values[j] : string.Empty;
            }

            result.Add(record);
        }

        return result;
    }
}

public sealed class JsonParser : DataParser
{
    protected override List<Dictionary<string, string>> ParseCore(string input)
    {
        using var document = JsonDocument.Parse(input);
        var result = new List<Dictionary<string, string>>();

        if (document.RootElement.ValueKind != JsonValueKind.Array)
            throw new FormatException("JSON input must be an array of objects.");

        foreach (var item in document.RootElement.EnumerateArray())
        {
            if (item.ValueKind != JsonValueKind.Object)
                continue;

            var record = new Dictionary<string, string>();

            foreach (var property in item.EnumerateObject())
            {
                record[property.Name] = property.Value.ToString();
            }

            result.Add(record);
        }

        return result;
    }
}

public static class Demo
{
    public static void Main()
    {
        DataParser csvParser = new CsvParser();
        var csvData = "name,age\nAlice,30\nBob,25";
        var csvResult = csvParser.Parse(csvData);

        DataParser jsonParser = new JsonParser();
        var jsonData = "[{\"name\":\"Alice\",\"age\":\"30\"},{\"name\":\"Bob\",\"age\":\"25\"}]";
        var jsonResult = jsonParser.Parse(jsonData);

        Print("CSV", csvResult);
        Print("JSON", jsonResult);
    }

    private static void Print(string label, List<Dictionary<string, string>> records)
    {
        Console.WriteLine(label);
        foreach (var record in records)
        {
            Console.WriteLine(string.Join(", ", record.Select(kvp => $"{kvp.Key}={kvp.Value}")));
        }
        Console.WriteLine();
    }
}
```

Why this is Template Method:
- `DataParser.Parse()` is the template method
- it defines the fixed algorithm
- `ParseCore()` is the required variable step
- `Validate()` and `Transform()` are optional hooks subclasses can override

If you want, I can also show a version with interfaces, unit tests, or a more realistic CSV parser with quoted fields.

