The repository pattern separates domain/business logic from data access by putting persistence behind a small interface. Your application code talks to a repository like `add()`, `get_by_id()`, or `list_all()` instead of knowing whether data comes from memory, SQL, or an API. That makes code easier to test, swap storage backends, and keep business logic focused on entities rather than queries.

```python
from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Dict, Generic, List, Optional, TypeVar


T = TypeVar("T")
ID = TypeVar("ID")


@dataclass(frozen=True)
class User:
    id: int
    name: str


class Repository(ABC, Generic[T, ID]):
    @abstractmethod
    def add(self, entity: T) -> None:
        raise NotImplementedError

    @abstractmethod
    def get_by_id(self, entity_id: ID) -> Optional[T]:
        raise NotImplementedError

    @abstractmethod
    def list_all(self) -> List[T]:
        raise NotImplementedError


class InMemoryRepository(Repository[T, ID]):
    def __init__(self) -> None:
        self._items: Dict[ID, T] = {}

    def add(self, entity: T) -> None:
        entity_id = getattr(entity, "id")
        self._items[entity_id] = entity

    def get_by_id(self, entity_id: ID) -> Optional[T]:
        return self._items.get(entity_id)

    def list_all(self) -> List[T]:
        return list(self._items.values())


if __name__ == "__main__":
    repo = InMemoryRepository[User, int]()

    repo.add(User(id=1, name="Alice"))
    repo.add(User(id=2, name="Bob"))

    print(repo.get_by_id(1))
    print(repo.list_all())
```

If you want, I can also show a version with `Protocol`, duplicate-id protection, or unit tests.

