Middleware chaining passes a request through a sequence of functions, where each middleware can inspect or modify the request/response, stop the flow, or delegate to the next middleware.

```js
const middlewares = [];

function use(middleware) {
  middlewares.push(middleware);
}

function runMiddlewares(req, res) {
  let index = -1;

  function dispatch(i) {
    if (i <= index) {
      return Promise.reject(new Error('next() called multiple times'));
    }

    index = i;
    const middleware = middlewares[i];

    if (!middleware) {
      return Promise.resolve();
    }

    try {
      return Promise.resolve(middleware(req, res, () => dispatch(i + 1)));
    } catch (error) {
      return Promise.reject(error);
    }
  }

  return dispatch(0);
}

use((req, res, next) => {
  console.log(`[LOG] ${req.method} ${req.url}`);
  next();
});

use((req, res, next) => {
  const token = req.headers.authorization;

  if (token !== 'Bearer secret-token') {
    res.statusCode = 401;
    res.body = { error: 'Unauthorized' };
    return;
  }

  req.user = { id: 1, role: 'admin' };
  next();
});

use((req, res) => {
  res.statusCode = 200;
  res.body = {
    message: 'Request handled successfully',
    user: req.user,
  };
});

async function simulate(req) {
  const res = { statusCode: 404, body: { error: 'Not found' } };

  try {
    await runMiddlewares(req, res);
  } catch (error) {
    res.statusCode = 500;
    res.body = { error: error.message };
  }

  console.log('Response:', res);
}

simulate({
  method: 'GET',
  url: '/profile',
  headers: { authorization: 'Bearer secret-token' },
});

simulate({
  method: 'GET',
  url: '/profile',
  headers: {},
});
```

How it works:
- `use()` registers middleware in order.
- `runMiddlewares()` calls them one by one.
- Each middleware receives `(req, res, next)`.
- Calling `next()` continues the chain.
- Authentication can stop the chain by not calling `next()`.
- The final handler writes the response.

