Consistent hashing maps both nodes and keys onto the same circular hash space. A key is assigned to the first node clockwise from the key’s hash. When a node is added or removed, only the keys that fall between that node and its predecessor usually move, so remapping is minimal compared with modulo-based sharding.

Virtual nodes improve balance. Instead of placing each real node on the ring once, you place it many times using distinct hashes like `node#0`, `node#1`, etc. This spreads each physical node around the ring, reducing hot spots and making uneven node counts less problematic.

Here’s a simple Python implementation for string keys and string node names:

```python
import bisect
import hashlib
from typing import Dict, List, Tuple


class ConsistentHashRing:
    def __init__(self, nodes: List[str] | None = None, virtual_nodes: int = 100):
        if virtual_nodes <= 0:
            raise ValueError("virtual_nodes must be > 0")
        self.virtual_nodes = virtual_nodes
        self.ring: List[Tuple[int, str]] = []
        self._hashes: List[int] = []
        self._node_points: Dict[str, List[int]] = {}

        for node in nodes or []:
            self.add_node(node)

    @staticmethod
    def _hash(value: str) -> int:
        digest = hashlib.sha256(value.encode("utf-8")).digest()
        return int.from_bytes(digest[:8], "big")

    def add_node(self, node: str) -> None:
        if node in self._node_points:
            raise ValueError(f"node already exists: {node}")

        points = []
        for i in range(self.virtual_nodes):
            point = self._hash(f"{node}#{i}")
            bisect.insort(self.ring, (point, node))
            points.append(point)

        self._node_points[node] = points
        self._hashes = [point for point, _ in self.ring]

    def remove_node(self, node: str) -> None:
        points = self._node_points.pop(node, None)
        if points is None:
            raise ValueError(f"node does not exist: {node}")

        point_set = set(points)
        self.ring = [(point, n) for point, n in self.ring if not (n == node and point in point_set)]
        self._hashes = [point for point, _ in self.ring]

    def get_node(self, key: str) -> str:
        if not self.ring:
            raise ValueError("hash ring is empty")

        key_hash = self._hash(key)
        idx = bisect.bisect_left(self._hashes, key_hash)
        if idx == len(self._hashes):
            idx = 0
        return self.ring[idx][1]

    def get_ring(self) -> List[Tuple[int, str]]:
        return list(self.ring)


if __name__ == "__main__":
    ring = ConsistentHashRing(["node-a", "node-b", "node-c"], virtual_nodes=50)

    keys = ["user:1", "user:2", "order:99", "session:abc"]
    for key in keys:
        print(f"{key} -> {ring.get_node(key)}")

    print("Adding node-d...")
    ring.add_node("node-d")
    for key in keys:
        print(f"{key} -> {ring.get_node(key)}")
```

How it works:
- `add_node`: places many virtual positions for the same real node on the ring.
- `get_node`: hashes the key, finds the first ring point `>= key_hash`, and wraps to the first point if needed.
- `remove_node`: deletes that node’s virtual points.

