function stringifyWithCircularPaths(value, space) {
  const seen = new WeakMap();

  return JSON.stringify(
    value,
    function replacer(key, currentValue) {
      if (currentValue === null || typeof currentValue !== 'object') {
        return currentValue;
      }

      const parentPath = seen.get(this) ?? '$';
      const currentPath = key === ''
        ? '$'
        : Array.isArray(this)
          ? `${parentPath}[${key}]`
          : /^[A-Za-z_$][\w$]*$/.test(key)
            ? `${parentPath}.${key}`
            : `${parentPath}[${JSON.stringify(key)}]`;

      if (seen.has(currentValue)) {
        return { $ref: seen.get(currentValue) };
      }

      seen.set(currentValue, currentPath);
      return currentValue;
    },
    space
  );
}

