function deepStructuralEqual(a, b) {
  if (Object.is(a, b)) return true;

  const isObjectLike = (v) => v !== null && (typeof v === 'object' || typeof v === 'function');
  if (!isObjectLike(a) || !isObjectLike(b)) return false;

  const seen = new WeakMap();
  const stack = [[a, b]];

  while (stack.length) {
    const [x, y] = stack.pop();

    if (Object.is(x, y)) continue;
    if (!isObjectLike(x) || !isObjectLike(y)) return false;

    const xTag = Object.prototype.toString.call(x);
    const yTag = Object.prototype.toString.call(y);
    if (xTag !== yTag) return false;

    let mapped = seen.get(x);
    if (mapped) {
      if (mapped !== y) return false;
      continue;
    }
    seen.set(x, y);

    if (xTag === '[object Date]') {
      if (!Object.is(x.getTime(), y.getTime())) return false;
      continue;
    }

    if (xTag === '[object RegExp]') {
      if (x.source !== y.source || x.flags !== y.flags) return false;
      continue;
    }

    if (xTag === '[object ArrayBuffer]') {
      if (x.byteLength !== y.byteLength) return false;
      const vx = new Uint8Array(x);
      const vy = new Uint8Array(y);
      for (let i = 0; i < vx.length; i++) {
        if (vx[i] !== vy[i]) return false;
      }
      continue;
    }

    if (ArrayBuffer.isView(x)) {
      if (x.constructor !== y.constructor || x.length !== y.length) return false;
      for (let i = 0; i < x.length; i++) {
        if (!Object.is(x[i], y[i])) return false;
      }
      continue;
    }

    if (xTag === '[object Map]') {
      if (x.size !== y.size) return false;

      const yEntries = Array.from(y.entries());
      const used = new Array(yEntries.length).fill(false);

      outerMap: for (const [kx, vx] of x) {
        for (let i = 0; i < yEntries.length; i++) {
          if (used[i]) continue;
          const [ky, vy] = yEntries[i];
          if (!deepStructuralEqual(kx, ky)) continue;
          if (!deepStructuralEqual(vx, vy)) continue;
          used[i] = true;
          continue outerMap;
        }
        return false;
      }
      continue;
    }

    if (xTag === '[object Set]') {
      if (x.size !== y.size) return false;

      const yValues = Array.from(y.values());
      const used = new Array(yValues.length).fill(false);

      outerSet: for (const vx of x) {
        for (let i = 0; i < yValues.length; i++) {
          if (used[i]) continue;
          if (!deepStructuralEqual(vx, yValues[i])) continue;
          used[i] = true;
          continue outerSet;
        }
        return false;
      }
      continue;
    }

    if (Object.getPrototypeOf(x) !== Object.getPrototypeOf(y)) return false;

    const xKeys = Reflect.ownKeys(x);
    const yKeys = Reflect.ownKeys(y);
    if (xKeys.length !== yKeys.length) return false;

    for (let i = 0; i < xKeys.length; i++) {
      if (!Object.prototype.hasOwnProperty.call(y, xKeys[i])) return false;
    }

    for (let i = 0; i < xKeys.length; i++) {
      const key = xKeys[i];
      const dx = Object.getOwnPropertyDescriptor(x, key);
      const dy = Object.getOwnPropertyDescriptor(y, key);

      if (!dy) return false;
      if (dx.enumerable !== dy.enumerable || dx.configurable !== dy.configurable) return false;

      const xIsData = Object.prototype.hasOwnProperty.call(dx, 'value');
      const yIsData = Object.prototype.hasOwnProperty.call(dy, 'value');
      if (xIsData !== yIsData) return false;

      if (xIsData) {
        if (dx.writable !== dy.writable) return false;
        stack.push([dx.value, dy.value]);
      } else {
        if (!Object.is(dx.get, dy.get) || !Object.is(dx.set, dy.set)) return false;
      }
    }
  }

  return true;
}
```

This avoids stack overflow by using an explicit heap stack instead of recursion, and it handles cycles/shared subtrees by memoizing object-pair identity in a `WeakMap`.

