function flattenObject(input) {
  const out = {};

  const escapeSegment = (segment) =>
    String(segment)
      .replace(/\\/g, "\\\\")
      .replace(/\./g, "\\.");

  const joinPath = (parts) => parts.map(escapeSegment).join(".");

  const visit = (value, pathParts) => {
    if (Array.isArray(value)) {
      if (value.length === 0) {
        out[joinPath(pathParts)] = [];
        return;
      }

      value.forEach((item, index) => {
        visit(item, [...pathParts, String(index)]);
      });
      return;
    }

    if (value && typeof value === "object") {
      const entries = Object.entries(value);
      if (entries.length === 0) {
        out[joinPath(pathParts)] = {};
        return;
      }

      for (const [key, child] of entries) {
        visit(child, [...pathParts, key]);
      }
      return;
    }

    out[joinPath(pathParts)] = value;
  };

  for (const [key, value] of Object.entries(input)) {
    visit(value, [key]);
  }

  return out;
}
```

Escaping strategy:
- Path separator is `.`.
- In each original key segment, escape `\\` as `\\\\` first.
- Then escape literal `.` as `\\.`.
- Join escaped segments with `.`.
- Array indexes are emitted as normal path segments (`items.0.name`).
- Empty objects and empty arrays are preserved as terminal values.

Example:

```js
