  "a.b": {
    c: 1,
    emptyObj: {},
    emptyArr: [],
  },
  plain: [{ "x.y": 2 }],
  "back\\slash.key": 3,
};

console.log(flattenObject(input));
/*
{
  'a\\.b.c': 1,
  'a\\.b.emptyObj': {},
  'a\\.b.emptyArr': [],
  'plain.0.x\\.y': 2,
  'back\\\\slash\\.key': 3
}
*/
```

