Use grade-school arithmetic on strings. For `a`, `b`, `c` up to 10,000 digits, compare/multiply/add as digit arrays or strings and never parse into native numbers.

```js
function stripLeadingZeros(s) {
  s = s.replace(/^0+/, '');
  return s === '' ? '0' : s;
}

function compareStrings(a, b) {
  a = stripLeadingZeros(a);
  b = stripLeadingZeros(b);
  if (a.length !== b.length) return a.length < b.length ? -1 : 1;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

function addStrings(a, b) {
  a = stripLeadingZeros(a);
  b = stripLeadingZeros(b);
  let i = a.length - 1;
  let j = b.length - 1;
  let carry = 0;
  let out = '';

  while (i >= 0 || j >= 0 || carry) {
    const da = i >= 0 ? a.charCodeAt(i) - 48 : 0;
    const db = j >= 0 ? b.charCodeAt(j) - 48 : 0;
    const sum = da + db + carry;
    out = String(sum % 10) + out;
    carry = Math.floor(sum / 10);
    i--;
    j--;
  }

  return stripLeadingZeros(out);
}

function multiplyStrings(a, b) {
  a = stripLeadingZeros(a);
  b = stripLeadingZeros(b);
  if (a === '0' || b === '0') return '0';

  const m = a.length;
  const n = b.length;
  const res = new Array(m + n).fill(0);

  for (let i = m - 1; i >= 0; i--) {
    const da = a.charCodeAt(i) - 48;
    for (let j = n - 1; j >= 0; j--) {
      const db = b.charCodeAt(j) - 48;
      const idx = i + j + 1;
      const prod = da * db + res[idx];
      res[idx] = prod % 10;
      res[idx - 1] += Math.floor(prod / 10);
    }
  }

  for (let k = m + n - 1; k > 0; k--) {
    if (res[k] >= 10) {
      res[k - 1] += Math.floor(res[k] / 10);
      res[k] %= 10;
    }
  }

  return stripLeadingZeros(res.join(''));
}

// Example: compute a*b + c
function compute(a, b, c) {
  return addStrings(multiplyStrings(a, b), c);
}
