  if (digits.length <= scale) {
    digits = digits.padStart(scale + 1, '0');
  }

  const intPart = digits.slice(0, -scale) || '0';
  let fracPart = digits.slice(-scale);

  fracPart = fracPart.replace(/0+$/, '');

  return fracPart
    ? `${negative ? '-' : ''}${intPart}.${fracPart}`
    : `${negative ? '-' : ''}${intPart}`;
}

// Examples
