function roundDecimalString(value, places) {
  if (!Number.isInteger(places) || places < 0) {
    throw new RangeError('places must be a non-negative integer');
  }
  if (typeof value !== 'string') {
    throw new TypeError('value must be a string');
  }

  const match = value.trim().match(/^([+-]?)(\d+)(?:\.(\d+))?$/);
  if (!match) {
    throw new Error('invalid decimal string');
  }

  const [, sign, intPartRaw, fracRaw = ''] = match;
  const negative = sign === '-';
  const scale = BigInt(10) ** BigInt(places);
  const digits = intPartRaw + fracRaw;
  const numerator = digits === '' ? 0n : BigInt(digits);
  const denominator = BigInt(10) ** BigInt(fracRaw.length);

  let scaled = numerator * scale;
  const quotient = scaled / denominator;
  const remainder = scaled % denominator;
  const twiceRemainder = remainder * 2n;

  let rounded = quotient;
  if (twiceRemainder > denominator) {
    rounded += 1n;
  } else if (twiceRemainder === denominator && (quotient % 2n !== 0n)) {
    rounded += 1n;
  }

  const factor = scale;
  const intPart = rounded / factor;
  const fracPart = rounded % factor;
  const fracText = places === 0 ? '' : '.' + fracPart.toString().padStart(places, '0');
  return `${negative && rounded !== 0n ? '-' : ''}${intPart.toString()}${fracText}`;
}

// Tests
console.log(roundDecimalString('1.25', 1)); // 1.2
console.log(roundDecimalString('1.35', 1)); // 1.4
console.log(roundDecimalString('1.15', 1)); // 1.2
console.log(roundDecimalString('2.5', 0));  // 2
console.log(roundDecimalString('3.5', 0));  // 4
