function normalizeMinutes(value) {
  const day = 24 * 60;
  return ((value % day) + day) % day;
}

function expandInterval(startMinutes, endMinutes, startInclusive = true, endInclusive = false) {
  const day = 24 * 60;
  const start = normalizeMinutes(startMinutes);
  const end = normalizeMinutes(endMinutes);
  const wraps = end < start || (end === start && (startInclusive || endInclusive));

  if (!wraps) {
    return [{ start, end, startInclusive, endInclusive }];
  }

  return [
    { start, end: day, startInclusive, endInclusive: false },
    { start: 0, end, startInclusive: true, endInclusive },
  ];
}

function segmentsOverlap(a, b) {
  const left = Math.max(a.start, b.start);
  const right = Math.min(a.end, b.end);

  if (left < right) return true;
  if (left > right) return false;

  const aIncludes = left === a.start ? a.startInclusive : a.endInclusive;
  const bIncludes = left === b.start ? b.startInclusive : b.endInclusive;
  return aIncludes && bIncludes;
}

function intervalsOverlap(a, b) {
  const aParts = expandInterval(a.start, a.end, a.startInclusive, a.endInclusive);
  const bParts = expandInterval(b.start, b.end, b.startInclusive, b.endInclusive);

  for (const aPart of aParts) {
    for (const bPart of bParts) {
      if (segmentsOverlap(aPart, bPart)) return true;
    }
  }

  return false;
}

// Examples:
intervalsOverlap(
  { start: 60, end: 120, startInclusive: true, endInclusive: false },
  { start: 120, end: 180, startInclusive: true, endInclusive: true }
); // false

intervalsOverlap(
  { start: 60, end: 120, startInclusive: true, endInclusive: true },
  { start: 120, end: 180, startInclusive: true, endInclusive: false }
); // true

intervalsOverlap(
  { start: 23 * 60, end: 60, startInclusive: true, endInclusive: false },
  { start: 30, end: 90, startInclusive: true, endInclusive: false }
); // true

intervalsOverlap(
  { start: 300, end: 300, startInclusive: true, endInclusive: true },
  { start: 300, end: 360, startInclusive: false, endInclusive: false }
); // true
```

