type PaginationResult = {
  page: number;
  pageSize: number;
  totalItems: bigint;
  totalPages: bigint;
  hasPrevious: boolean;
  hasNext: boolean;
  offset: bigint;
  limit: number;
  itemsOnPage: bigint;
  isValid: boolean;
  error: null | 'INVALID_PAGE_SIZE' | 'INVALID_PAGE_NUMBER';
};

export function paginate(
  totalItemsInput: number | bigint,
  pageInput: number,
  pageSizeInput: number,
): PaginationResult {
  const totalItems = typeof totalItemsInput === 'bigint'
    ? totalItemsInput
    : BigInt(Math.max(0, Math.trunc(totalItemsInput)));

  const page = Math.trunc(pageInput);
  const pageSize = Math.trunc(pageSizeInput);

  if (pageSize <= 0) {
    return {
      page: page < 1 ? 1 : page,
      pageSize,
      totalItems,
      totalPages: 0n,
      hasPrevious: false,
      hasNext: false,
      offset: 0n,
      limit: 0,
      itemsOnPage: 0n,
      isValid: false,
      error: 'INVALID_PAGE_SIZE',
    };
  }

  if (page < 1) {
    return {
      page,
      pageSize,
      totalItems,
      totalPages: totalItems === 0n ? 0n : (totalItems + BigInt(pageSize) - 1n) / BigInt(pageSize),
      hasPrevious: false,
      hasNext: totalItems > 0n,
      offset: 0n,
      limit: pageSize,
      itemsOnPage: 0n,
      isValid: false,
      error: 'INVALID_PAGE_NUMBER',
    };
  }

  const pageSizeBig = BigInt(pageSize);
  const totalPages = totalItems === 0n ? 0n : (totalItems + pageSizeBig - 1n) / pageSizeBig;
  const offset = BigInt(page - 1) * pageSizeBig;

  let itemsOnPage = 0n;
  if (offset < totalItems) {
    const remaining = totalItems - offset;
    itemsOnPage = remaining < pageSizeBig ? remaining : pageSizeBig;
  }

  return {
    page,
    pageSize,
    totalItems,
    totalPages,
    hasPrevious: page > 1 && totalPages > 0n,
    hasNext: BigInt(page) < totalPages,
    offset,
    limit: pageSize,
    itemsOnPage,
    isValid: true,
    error: null,
  };
}
```

Exact invalid-return rules:

- `pageSize <= 0` → `isValid: false`, `error: 'INVALID_PAGE_SIZE'`, `totalPages: 0n`, `offset: 0n`, `limit: 0`, `itemsOnPage: 0n`, `hasPrevious: false`, `hasNext: false`
- `page < 1` with valid page size → `isValid: false`, `error: 'INVALID_PAGE_NUMBER'`, `offset: 0n`, `itemsOnPage: 0n`, `limit: pageSize`, `hasPrevious: false`, `hasNext: totalItems > 0n`
- Empty dataset (`totalItems = 0`) with valid inputs → valid result with `totalPages: 0n`, `itemsOnPage: 0n`, `hasPrevious: false`, `hasNext: false`
- Requesting a page beyond the last page is treated as valid but empty: `itemsOnPage: 0n`, `hasNext: false`

Example outputs:

```ts
paginate(0n, 1, 20)
// {
//   page: 1,
//   pageSize: 20,
//   totalItems: 0n,
//   totalPages: 0n,
//   hasPrevious: false,
//   hasNext: false,
//   offset: 0n,
//   limit: 20,
//   itemsOnPage: 0n,
//   isValid: true,
//   error: null
// }

paginate(100n, -2, 20)
// invalid page number

paginate(100n, 1, 0)
// invalid page size

paginate(10_000_000_000n, 2, 25)
// works safely because totals and offsets use bigint
```

