function parseAndValidateIPv6(input) {
  if (typeof input !== 'string') return { valid: false, error: 'Input must be a string' };

  const value = input.trim();
  if (!value) return { valid: false, error: 'Empty input' };

  if ((value.match(/::/g) || []).length > 1) {
    return { valid: false, error: 'IPv6 address cannot contain multiple :: compressions' };
  }

  const hasIPv4 = value.includes('.');
  let parts = [];

  const parseIPv4 = (s) => {
    const octets = s.split('.');
    if (octets.length !== 4) return null;
    const nums = [];
    for (const octet of octets) {
      if (!/^\d+$/.test(octet)) return null;
      if (octet.length > 1 && octet[0] === '0') return null;
      const n = Number(octet);
      if (n < 0 || n > 255) return null;
      nums.push(n);
    }
    return [((nums[0] << 8) | nums[1]).toString(16), ((nums[2] << 8) | nums[3]).toString(16)];
  };

  let working = value;
  if (hasIPv4) {
    const lastColon = value.lastIndexOf(':');
    if (lastColon === -1) return { valid: false, error: 'Invalid mixed IPv6/IPv4 form' };
    const ipv4Part = value.slice(lastColon + 1);
    const ipv4Hextets = parseIPv4(ipv4Part);
    if (!ipv4Hextets) return { valid: false, error: 'Invalid embedded IPv4 address' };
    working = value.slice(0, lastColon) + ':' + ipv4Hextets.join(':');
  }

  const halves = working.split('::');
  if (halves.length > 2) {
    return { valid: false, error: 'IPv6 address cannot contain multiple :: compressions' };
  }

  const left = halves[0] ? halves[0].split(':') : [];
  const right = halves[1] ? halves[1].split(':') : [];

  const allParts = [...left, ...right];
  for (const part of allParts) {
    if (!part) return { valid: false, error: 'Invalid empty hextet' };
    if (!/^[0-9a-fA-F]{1,4}$/.test(part)) {
      return { valid: false, error: `Invalid hextet: ${part}` };
    }
  }

  if (halves.length === 1) {
    if (allParts.length !== 8) {
      return { valid: false, error: 'IPv6 address must contain exactly 8 hextets when :: is not used' };
    }
    parts = allParts;
  } else {
    const missing = 8 - (left.length + right.length);
    if (missing < 1) {
      return { valid: false, error: 'Invalid :: compression usage' };
    }
    parts = [...left, ...Array(missing).fill('0'), ...right];
  }

  if (parts.length !== 8) {
    return { valid: false, error: 'IPv6 address must expand to exactly 8 hextets' };
  }

  const normalized = parts.map((part) => parseInt(part, 16).toString(16));

  let bestStart = -1;
  let bestLen = 0;
  for (let i = 0; i < normalized.length; ) {
    if (normalized[i] !== '0') {
      i++;
      continue;
    }
    let j = i;
    while (j < normalized.length && normalized[j] === '0') j++;
    const len = j - i;
    if (len > bestLen && len >= 2) {
      bestStart = i;
      bestLen = len;
    }
    i = j;
  }

  let canonical;
  if (bestStart === -1) {
    canonical = normalized.join(':');
  } else {
    const leftSide = normalized.slice(0, bestStart).join(':');
    const rightSide = normalized.slice(bestStart + bestLen).join(':');
    canonical = `${leftSide}::${rightSide}`;
    if (!leftSide) canonical = canonical.replace(/^:/, '');
    if (!rightSide) canonical = canonical.replace(/:$/, '');
    if (canonical === ':') canonical = '::';
  }

  return {
    valid: true,
    canonical,
    expanded: normalized.map((part) => part.padStart(4, '0')).join(':'),
    hextets: normalized,
  };
}

// Example cases
const samples = [
  '2001:0DB8:0000:0000:0000:ff00:0042:8329',
  '2001:db8::ff00:42:8329',
  '::1',
  '::',
  '::ffff:192.168.0.1',
  '2001::25de::cade',
  '2001:db8:0:0:0:0:2:1',
];

for (const s of samples) {
  console.log(s, '=>', parseAndValidateIPv6(s));
}
```

Canonicalization rules used:
- lowercase hex
- remove leading zeros in each hextet
- compress the longest run of zero hextets with `::`
- if tied, compress the first longest run
- reject multiple `::`
- support embedded IPv4 by converting it to the final two hextets

