class Node {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.prev = null;
    this.next = null;
  }
}

class LRUCache {
  constructor(capacity) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new Error('capacity must be a non-negative integer');
    }

    this.capacity = capacity;
    this.map = new Map();
    this.head = new Node(null, null);
    this.tail = new Node(null, null);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key) {
    const node = this.map.get(key);
    if (!node) return undefined;
    this.#moveToFront(node);
    return node.value;
  }

  set(key, value) {
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing) {
      existing.value = value;
      this.#moveToFront(existing);
      return;
    }

    const node = new Node(key, value);
    this.map.set(key, node);
    this.#insertAfterHead(node);

    if (this.map.size > this.capacity) {
      const lru = this.tail.prev;
      this.#removeNode(lru);
      this.map.delete(lru.key);
    }
  }

  has(key) {
    return this.map.has(key);
  }

  #moveToFront(node) {
    this.#removeNode(node);
    this.#insertAfterHead(node);
  }

  #insertAfterHead(node) {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next.prev = node;
    this.head.next = node;
  }

  #removeNode(node) {
    node.prev.next = node.next;
    node.next.prev = node.prev;
  }
}

// Minimal verification
(function test() {
  const assert = (condition, message) => {
    if (!condition) throw new Error(message);
  };

  // capacity 0
  const c0 = new LRUCache(0);
  c0.set('a', 1);
  assert(c0.get('a') === undefined, 'capacity 0 should never store values');

  // capacity 1
  const c1 = new LRUCache(1);
  c1.set('a', 1);
  assert(c1.get('a') === 1, 'should store first value');
  c1.set('b', 2);
  assert(c1.get('a') === undefined, 'should evict previous key at capacity 1');
  assert(c1.get('b') === 2, 'should keep most recent key');

  // repeated inserts of same key
  const same = new LRUCache(2);
  same.set('x', 1);
  same.set('x', 2);
  same.set('x', 3);
  assert(same.get('x') === 3, 'same key should update in place');
  same.set('y', 9);
  same.set('z', 10);
  assert(same.get('x') === undefined, 'updated key should still participate in LRU order');

  // falsy values
  const falsy = new LRUCache(2);
  falsy.set('n', null);
  falsy.set('u', undefined);
  assert(falsy.has('n') === true, 'null value key should exist');
  assert(falsy.has('u') === true, 'undefined value key should exist');
  assert(falsy.get('n') === null, 'should return null exactly');
  assert(falsy.get('u') === undefined, 'should return undefined exactly');

  console.log('All tests passed');
})();
```

