```js
function topologicalSort(graph) {
  const state = new Map(); // 0 = unvisited, 1 = visiting, 2 = visited
  const order = [];
  const stack = [];
  const stackIndex = new Map();

  const nodes = new Set();
  for (const [node, deps] of Object.entries(graph)) {
    nodes.add(node);
    for (const dep of deps) nodes.add(dep);
  }

  function dfs(node) {
    state.set(node, 1);
    stackIndex.set(node, stack.length);
    stack.push(node);

    for (const dep of graph[node] || []) {
      const depState = state.get(dep) || 0;

      if (depState === 0) {
        const result = dfs(dep);
        if (!result.ok) return result;
      } else if (depState === 1) {
        const start = stackIndex.get(dep);
        return {
          ok: false,
          cycle: [...stack.slice(start), dep],
        };
      }
    }

    stack.pop();
    stackIndex.delete(node);
    state.set(node, 2);
    order.push(node);
    return { ok: true };
  }

  for (const node of nodes) {
    if ((state.get(node) || 0) === 0) {
      const result = dfs(node);
      if (!result.ok) return result;
    }
  }

  return {
    ok: true,
    order,
  };
}
```

Example behavior:

```js
topologicalSort({
  A: ["B", "C"],
  B: ["D"],
  C: [],
  D: [],
  E: ["F"],
  F: [],
});
// { ok: true, order: [ 'D', 'B', 'C', 'A', 'F', 'E' ] }

topologicalSort({
  A: ["A"],
});
// { ok: false, cycle: [ 'A', 'A' ] }

topologicalSort({
  A: ["B"],
  B: ["C"],
  C: ["A"],
});
// { ok: false, cycle: [ 'A', 'B', 'C', 'A' ] }
