```js
function evaluateExpression(input) {
  let i = 0;
  const n = input.length;
  const values = [];
  const ops = [];
  let expectOperand = true;

  const precedence = op => (op === '+' || op === '-') ? 1 : 2;

  const applyTop = () => {
    if (ops.length === 0 || values.length < 2) throw new Error('Malformed expression');
    const op = ops.pop();
    const b = values.pop();
    const a = values.pop();
    switch (op) {
      case '+': values.push(a + b); break;
      case '-': values.push(a - b); break;
      case '*': values.push(a * b); break;
      case '/':
        if (b === 0) throw new Error('Division by zero');
        values.push(a / b);
        break;
      default:
        throw new Error('Malformed expression');
    }
  };

  while (i < n) {
    const ch = input[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      i++;
      continue;
    }

    if (ch >= '0' && ch <= '9') {
      if (!expectOperand) throw new Error('Malformed expression');
      let num = 0;
      while (i < n && input[i] >= '0' && input[i] <= '9') {
        num = num * 10 + (input.charCodeAt(i) - 48);
        i++;
      }
      values.push(num);
      expectOperand = false;
      continue;
    }

    if (ch === '(') {
      if (!expectOperand) throw new Error('Malformed expression');
      ops.push(ch);
      i++;
      continue;
    }

    if (ch === ')') {
      if (expectOperand) throw new Error('Malformed expression'); // catches empty () and trailing operator before )
      while (ops.length && ops[ops.length - 1] !== '(') applyTop();
      if (ops.length === 0) throw new Error('Malformed expression');
      ops.pop();
      i++;
      expectOperand = false;
      continue;
    }

    if (ch === '+' || ch === '-' || ch === '*' || ch === '/') {
      if (expectOperand) throw new Error('Malformed expression'); // catches adjacent operators
      while (
        ops.length &&
        ops[ops.length - 1] !== '(' &&
        precedence(ops[ops.length - 1]) >= precedence(ch)
      ) {
        applyTop();
      }
      ops.push(ch);
      i++;
      expectOperand = true;
      continue;
    }

    throw new Error(`Invalid character: ${ch}`);
  }

  if (expectOperand) throw new Error('Malformed expression');

  while (ops.length) {
    if (ops[ops.length - 1] === '(') throw new Error('Malformed expression');
    applyTop();
  }

  if (values.length !== 1) throw new Error('Malformed expression');
  return values[0];
}
```

This uses an iterative stack-based parser/evaluator, so it handles nesting depth 50,000 without recursion. It rejects:
- `()` via `)` while still expecting an operand
- `1++2`, `1+*2`, etc. via operator handling while `expectOperand` is true
- `1(2)` or `)1` as malformed
- unmatched parentheses and trailing operators

