function stableJsonHash(value) {
  const seen = new Map();
  let nextRefId = 0;

  function serialize(node) {
    if (node === null) return 'null';

    const type = typeof node;

    if (type === 'number') {
      if (Number.isNaN(node)) return 'number:NaN';
      if (!Number.isFinite(node)) return node > 0 ? 'number:Infinity' : 'number:-Infinity';
      return Object.is(node, -0) ? 'number:-0' : `number:${node}`;
    }

    if (type === 'string') return `string:${JSON.stringify(node)}`;
    if (type === 'boolean') return `boolean:${node}`;
    if (type === 'undefined') return 'undefined';
    if (type === 'bigint') return `bigint:${node}n`;
    if (type === 'symbol') return `symbol:${String(node.description)}`;
    if (type === 'function') return `function:${node.name || '<anonymous>'}`;

    if (seen.has(node)) {
      return `ref:${seen.get(node)}`;
    }

    const refId = nextRefId++;
    seen.set(node, refId);

    if (Array.isArray(node)) {
      return `array#${refId}:[${node.map(serialize).join(',')}]`;
    }

    if (node instanceof Date) {
      return `date#${refId}:${Number.isNaN(node.getTime()) ? 'Invalid Date' : node.toISOString()}`;
    }

    if (node instanceof RegExp) {
      return `regexp#${refId}:${node.toString()}`;
    }

    const keys = Object.keys(node).sort();
    const entries = keys.map((key) => `${JSON.stringify(key)}:${serialize(node[key])}`);
    return `object#${refId}:{${entries.join(',')}}`;
  }

  const canonical = serialize(value);

  let hash = 0x811c9dc5;
  for (let i = 0; i < canonical.length; i++) {
    hash ^= canonical.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }

  return (hash >>> 0).toString(16).padStart(8, '0');
}
```

