```js
function diffJsonLike(a, b) {
  const changes = [];
  const seen = new WeakMap();

  walk(a, b, []);
  return changes;

  function walk(left, right, path) {
    if (Object.is(left, right)) return;

    const leftType = kindOf(left);
    const rightType = kindOf(right);

    if (leftType !== rightType) {
      changes.push({
        path: formatPath(path),
        type: 'type-change',
        beforeType: leftType,
        afterType: rightType,
        before: left,
        after: right,
      });
      return;
    }

    if (isPrimitiveType(leftType)) {
      changes.push({
        path: formatPath(path),
        type: 'value-change',
        before: left,
        after: right,
      });
      return;
    }

    if (leftType === 'array' || leftType === 'object') {
      if (isCircularPair(left, right)) return;
      rememberPair(left, right);
    }

    if (leftType === 'array') {
      diffArray(left, right, path);
      return;
    }

    if (leftType === 'object') {
      diffObject(left, right, path);
      return;
    }

    changes.push({
      path: formatPath(path),
      type: 'value-change',
      before: left,
      after: right,
    });
  }

  function diffObject(left, right, path) {
    const keys = new Set([...Object.keys(left), ...Object.keys(right)]);

    for (const key of keys) {
      const hasLeft = Object.prototype.hasOwnProperty.call(left, key);
      const hasRight = Object.prototype.hasOwnProperty.call(right, key);
      const nextPath = path.concat(key);

      if (!hasLeft && hasRight) {
        changes.push({
          path: formatPath(nextPath),
          type: 'add',
          after: right[key],
        });
        continue;
      }

      if (hasLeft && !hasRight) {
        changes.push({
          path: formatPath(nextPath),
          type: 'remove',
          before: left[key],
        });
        continue;
      }

      walk(left[key], right[key], nextPath);
    }
  }

  function diffArray(left, right, path) {
    const max = Math.max(left.length, right.length);

    for (let i = 0; i < max; i++) {
      const hasLeft = i in left;
      const hasRight = i in right;
      const nextPath = path.concat(i);

      if (!hasLeft && hasRight) {
        changes.push({
          path: formatPath(nextPath),
          type: 'add',
          after: right[i],
        });
        continue;
      }

      if (hasLeft && !hasRight) {
        changes.push({
          path: formatPath(nextPath),
          type: 'remove',
          before: left[i],
        });
        continue;
      }

      walk(left[i], right[i], nextPath);
    }

    if (left.length !== right.length) {
      changes.push({
        path: formatPath(path.concat('length')),
        type: 'value-change',
        before: left.length,
        after: right.length,
      });
    }
  }

  function kindOf(value) {
    if (value === null) return 'null';
    if (Array.isArray(value)) return 'array';
    return typeof value;
  }

  function isPrimitiveType(type) {
    return (
      type === 'null' ||
      type === 'undefined' ||
      type === 'string' ||
      type === 'number' ||
      type === 'boolean' ||
      type === 'bigint' ||
      type === 'symbol'
    );
  }

  function rememberPair(left, right) {
    let rights = seen.get(left);
    if (!rights) {
      rights = new WeakSet();
      seen.set(left, rights);
    }
    rights.add(right);
  }

  function isCircularPair(left, right) {
    const rights = seen.get(left);
    return !!rights && rights.has(right);
  }

  function formatPath(segments) {
    if (segments.length === 0) return '$';

    let out = '$';
    for (const segment of segments) {
      if (typeof segment === 'number') {
        out += `[${segment}]`;
      } else if (/^[A-Za-z_$][A-Za-z0-9_$]*$/.test(segment)) {
        out += `.${segment}`;
      } else {
        out += `[${JSON.stringify(String(segment))}]`;
      }
    }
    return out;
  }
}
