Parse the request body once at the boundary, pass the typed struct to helpers, and remove helper-level `json.Unmarshal` calls.

```go
package service

import (
	"encoding/json"
	"fmt"
)

type Payload struct {
	UserID string   `json:"user_id"`
	Action string   `json:"action"`
	Items  []string `json:"items"`
	Meta   Meta     `json:"meta"`
}

type Meta struct {
	TraceID string `json:"trace_id"`
	Source  string `json:"source"`
}

// Before
func Handle(raw []byte) error {
	if err := validate(raw); err != nil {
		return err
	}
	if err := authorize(raw); err != nil {
		return err
	}
	if err := process(raw); err != nil {
		return err
	}
	return nil
}

func validate(raw []byte) error {
	var p Payload
	if err := json.Unmarshal(raw, &p); err != nil {
		return err
	}
	if p.UserID == "" || p.Action == "" {
		return fmt.Errorf("missing required fields")
	}
	return nil
}

func authorize(raw []byte) error {
	var p Payload
	if err := json.Unmarshal(raw, &p); err != nil {
		return err
	}
	if p.Meta.Source == "blocked" {
		return fmt.Errorf("unauthorized")
	}
	return nil
}

func process(raw []byte) error {
	var p Payload
	if err := json.Unmarshal(raw, &p); err != nil {
		return err
	}
	for _, item := range p.Items {
		_ = item // business logic
	}
	return nil
}
```

