func handle(w http.ResponseWriter, r *http.Request) {
    scanner := bufio.NewScanner(r.Body)
    for scanner.Scan() {
        line := scanner.Bytes() // avoids copying into a new string up front

        i := bytes.IndexByte(line, ',')
        if i < 0 {
            continue
        }
        j := bytes.IndexByte(line[i+1:], ',')
        if j < 0 {
            continue
        }
        j += i + 1

        id := bytes.TrimSpace(line[:i])
        kind := bytes.TrimSpace(line[i+1 : j])
        value := bytes.TrimSpace(line[j+1:])

        processRecordBytes(id, kind, value)
    }
}
```

