    for scanner.Scan() {
        line := scanner.Bytes()

        i := bytes.IndexByte(line, ',')
        if i < 0 {
            continue
        }
        j := bytes.IndexByte(line[i+1:], ',')
        if j < 0 {
            continue
        }
        j += i + 1

        id := string(bytes.TrimSpace(line[:i]))
        kind := string(bytes.TrimSpace(line[i+1 : j]))
        value := string(bytes.TrimSpace(line[j+1:]))

        processRecord(id, kind, value)
    }
}
```

That still allocates 3 strings per valid record, but removes the temporary slice allocation and avoids splitting the whole line.

